policies.inbound:




    @{
        var traceId = context.RequestId.ToString("N");
        var spanId = Guid.NewGuid().ToString("N").Substring(0, 16);
        return $"00-{traceId}-{spanId}-01";
    }


    @($"apim={context.Deployment.ServiceName}")





        {{mcp-app-client-id}}




            mcp.access









    {{function-app-url}}/api/input-check
    POST

        application/json



        @(context.RequestId.ToString())

    @(context.Request.Body.As(preserveContent: true))








                application/json

            @{
                return new JObject(
                    new JProperty("error", "Security check service unavailable"),
                    new JProperty("code", "SECURITY_CHECK_FAILED")
                ).ToString();
            }





<set-variable name="inputCheckBody" value="@(((IResponse)context.Variables["inputCheck"]).Body.As(preserveContent: true))" />


    <when condition="@(!((JObject)context.Variables["inputCheckBody"])["allowed"].Value())">



                application/json

            @{
                var result = (JObject)context.Variables["inputCheckBody"];
                return new JObject(
                    new JProperty("error", "Request blocked by security filter"),
                    new JProperty("reason", result["reason"]?.ToString() ?? "Unknown"),
                    new JProperty("category", result["category"]?.ToString() ?? "Unknown")
                ).ToString();
            }

return-response.set-body:
@{
                        var gatewayUrl = "{{apim-gateway-url}}";
                        var apiPath = context.Api.Path.TrimStart('/');
                        var prmUrl = gatewayUrl + "/" + apiPath + "/.well-known/oauth-protected-resource";
                        return JsonConvert.SerializeObject(new {
                            error = "unauthorized",
                            message = "Valid OAuth token required",
                            resource_metadata = prmUrl
                        });
                    }
